public class SearchCaseTimer {

    public int linearSearch(int[] arr, int target) {
        for (int i = 0; i < arr.length; i++) {
            if (arr[i] == target) return i;
        }
        return -1;
    }

    public long countBestCase(int n) {
        // Best case: target is arr[0]
        int[] arr = buildArray(n);
        int target = arr[0];
        long ops = 0;
        for (int i = 0; i < arr.length; i++) {
            ops++;
            if (arr[i] == target) break;
        }
        return ops;
    }

    public long countWorstCase(int n) {
        // TODO: target is arr[n-1] (last element), count comparisons
        return 0;
    }

    public long countAverageCase(int n) {
        // TODO: target is arr[n/2] (middle element), count comparisons
        return 0;
    }

    private int[] buildArray(int n) {
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) arr[i] = i + 1;
        return arr;
    }

    public void printCaseAnalysis(int n) {
        System.out.printf("n=%d | Best=%d | Average=%d | Worst=%d%n",
            n, countBestCase(n), countAverageCase(n), countWorstCase(n));
    }

    public static void main(String[] args) {
        SearchCaseTimer sct = new SearchCaseTimer();
        sct.printCaseAnalysis(10);
        sct.printCaseAnalysis(100);
        sct.printCaseAnalysis(1000);
    }
}

public class BubbleSortAnalyzer {

    // Optimized bubble sort that stops early if no swaps were made
    public long sortAndCount(int[] arr) {
        long comparisons = 0;
        int n = arr.length;
        for (int i = 0; i < n - 1; i++) {
            boolean swapped = false;
            for (int j = 0; j < n - i - 1; j++) {
                comparisons++;
                if (arr[j] > arr[j + 1]) {
                    int tmp = arr[j]; arr[j] = arr[j + 1]; arr[j + 1] = tmp;
                    swapped = true;
                }
            }
            if (!swapped) break; // early exit
        }
        return comparisons;
    }

