public class BinarySearchAnalyzer {

    public long binarySearchCount(int[] arr, int target) {
        int lo = 0, hi = arr.length - 1;
        long comparisons = 0;
        while (lo <= hi) {
            comparisons++;
            int mid = lo + (hi - lo) / 2;
            if (arr[mid] == target) return comparisons;
            else if (arr[mid] < target) lo = mid + 1;
            else hi = mid - 1;
        }
        return comparisons;
    }

    public long bestCase(int n) {
        // Target is the exact middle element
        int[] arr = buildSortedArray(n);
        int mid = arr[arr.length / 2];
        return binarySearchCount(arr, mid);
    }

    public long worstCase(int n) {
        // TODO: target is -1 (not in array), so search exhausts all steps
        return 0;
    }

    private int[] buildSortedArray(int n) {
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) arr[i] = i;
        return arr;
    }

    public void printCases(int n) {
        System.out.printf("n=%d | Best=%d | Worst=%d%n",
            n, bestCase(n), worstCase(n));
    }

    public static void main(String[] args) {
        BinarySearchAnalyzer bsa = new BinarySearchAnalyzer();
        bsa.printCases(8);
        bsa.printCases(16);
        bsa.printCases(1024);
    }
}
